class Solution {
    public String reformatNumber(String number) {
        String output = "";
        String[] parts = number.split(" ");
        for (String part : parts) {
            StringBuilder sb = new StringBuilder();
            int length = part.length();
            while (length >= 4) {
                sb.append(part);
                length -= 4;
            }
            output += sb.reverse() + "-";
        }
        return output;
    }
}
